// ============================================================
// РАНДОМНЫЙ ФОН — генерируется ОДИН РАЗ при первом вызове
// ============================================================

static std::string g_l2bg[Level2::HEIGHT_TILES][Level2::WIDTH_TILES];
static bool g_l2bgGenerated = false;

static void generateL2Bg() {
    if (g_l2bgGenerated) return;

    static const std::string BG_POOL[] = {
        "mwb1000","mwb2000","mwb3000","mwb4000",
        "mwb5000","mwb6000","mwb7000","mwb8000","mwb9000"
    };
    constexpr int POOL_SIZE = 9;

    for (int row = 0; row < Level2::HEIGHT_TILES; row++) {
        for (int col = 0; col < Level2::WIDTH_TILES; col++) {
            // Не нужен фон под стенами/полом — SOLID перекроет
            if (col == 0 || col == Level2::WIDTH_TILES-1 ||
                row == 0 || row == Level2::HEIGHT_TILES-1) {
                g_l2bg[row][col] = "";
            } else {
                g_l2bg[row][col] = BG_POOL[rand() % POOL_SIZE];
            }
        }
    }
    g_l2bgGenerated = true;
}

// ============================================================
// DRAW MAP
// ============================================================

void Level2::drawMap(SDL_Renderer* renderer, int camX, int camY) {
    SDL_Texture* tileset = TextureManager::getTexture("assets/map1/map1.png");

    int ox, oy;
    getL2MapOffset(ox, oy);

    // Экранный X = мировой X - camX + ox
    // (ox по X всегда 0, камера двигается, вычитая camX)
    const int screenOffX = ox - camX;
    const int screenOffY = oy - camY;

    if (!tileset) {
        SDL_SetRenderDrawColor(renderer, 40, 40, 50, 255);
        SDL_Rect fb = {screenOffX, screenOffY,
                       WIDTH_TILES * TILE_SIZE, HEIGHT_TILES * TILE_SIZE};
        SDL_RenderFillRect(renderer, &fb);
        return;
    }

    generateL2Bg();

    // Оптимизация: рисуем только видимые тайлы
    const int SW = Config::getWindowWidth();
    const int SH = Config::getWindowHeight();

    // Диапазон видимых столбцов
    int colStart = std::max(0, (camX - ox) / TILE_SIZE - 1);
    int colEnd   = std::min(WIDTH_TILES - 1, colStart + SW / TILE_SIZE + 2);

    // Диапазон видимых строк
    int rowStart = std::max(0, (camY - oy) / TILE_SIZE - 1);
    int rowEnd   = std::min(HEIGHT_TILES - 1, rowStart + SH / TILE_SIZE + 2);

    // СЛОЙ 1: фон
    for (int row = rowStart; row <= rowEnd; row++) {
        for (int col = colStart; col <= colEnd; col++) {
            if (g_l2bg[row][col].empty()) continue;
            drawTileByCode(renderer, tileset, g_l2bg[row][col],
                           screenOffX + col * TILE_SIZE,
                           screenOffY + row * TILE_SIZE);
        }
    }

    // СЛОЙ 2: solid
    for (int row = rowStart; row <= rowEnd; row++) {
        for (int col = colStart; col <= colEnd; col++) {
            if (LEVEL2_SOLID[row][col].empty()) continue;
            drawTileByCode(renderer, tileset, LEVEL2_SOLID[row][col],
                           screenOffX + col * TILE_SIZE,
                           screenOffY + row * TILE_SIZE);
        }
    }

    // СЛОЙ 3: декорации
    for (int row = rowStart; row <= rowEnd; row++) {
        for (int col = colStart; col <= colEnd; col++) {
            if (LEVEL2_DECO[row][col].empty()) continue;
            drawTileByCode(renderer, tileset, LEVEL2_DECO[row][col],
                           screenOffX + col * TILE_SIZE,
                           screenOffY + row * TILE_SIZE);
        }
    }
}

// ============================================================
// КОЛЛИЗИИ — работают в МИРОВЫХ координатах
// (playerX/Y — мировые, коллизии не зависят от камеры)
// ============================================================

bool Level2::isSolid(int worldX, int worldY) {
    int ox, oy;
    getL2MapOffset(ox, oy);

    int col = (worldX - ox) / TILE_SIZE;
    int row = (worldY - oy) / TILE_SIZE;

    // За пределами карты = стена
    if (col < 0 || col >= WIDTH_TILES || row < 0 || row >= HEIGHT_TILES)
        return true;

    const std::string& code = LEVEL2_SOLID[row][col];
    if (code.empty() || code.size() < 3) return false;

    // Платформы — только односторонняя коллизия сверху
    if (code.size() >= 2 && code[0] == 's' && code[1] == 'p') return false;

    // Шипы НЕ являются твёрдыми (они наносят урон отдельно, не блокируют)
    if (code.size() >= 2 && code[0] == 's' && code[1] == 't') return false;

    char shape = code[2];
    return (shape == 'w' || shape == 'f' || shape == 'c');
}

bool Level2::isPlatform(int worldX, int worldY) {
    int ox, oy;
    getL2MapOffset(ox, oy);

    int col = (worldX - ox) / TILE_SIZE;
    int row = (worldY - oy) / TILE_SIZE;

    if (col < 0 || col >= WIDTH_TILES || row < 0 || row >= HEIGHT_TILES)
        return false;

    const std::string& code = LEVEL2_SOLID[row][col];
    return (code.size() >= 2 && code[0] == 's' && code[1] == 'p');
}

void Level2::getMapOffset(int& outX, int& outY) {
    getL2MapOffset(outX, outY);
}

// ============================================================
// СПАВНЫ
// ============================================================

std::pair<float, float> Level2::getPlayerSpawn() {
    int ox, oy;
    getL2MapOffset(ox, oy);
    return {
        ox + L2_PLAYER_COL * TILE_SIZE + TILE_SIZE / 2.0f,
        oy + L2_PLAYER_ROW * TILE_SIZE + TILE_SIZE / 2.0f
    };
}

std::pair<float, float> Level2::getBossSpawn() {
    int ox, oy;
    getL2MapOffset(ox, oy);
    return {
        ox + L2_BOSS_COL * TILE_SIZE + TILE_SIZE / 2.0f,
        oy + L2_BOSS_ROW * TILE_SIZE + TILE_SIZE / 2.0f
    };
}

std::unique_ptr<Character> Level2::createBoss(float x, float y, float attackSpeedMult) {
    // NOTE(evol): Пока используем BossGolem — в будущем заменить на BossNinja
    return std::make_unique<BossGolem>(x, y, attackSpeedMult);
}